/* wms-inbound-ibordermaganer-sql-oracle.xml - selectIbHdInfoMap - 입고 헤더 정보 */
SELECT *
  FROM TWORK_INFO_IB_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = COALESCE(#{owkey}, #{sowkey})
   AND IBHDKEY = #{ibhdkey}

/* wms-inbound-ibordermaganer-sql-oracle.xml - selectIbDtInfoMap - 입고 상세 정보 Map */
SELECT *
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = COALESCE(#{owkey}, #{sowkey})
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

/* wms-inbound-ibordermaganer-sql-oracle.xml - selectIbcfDtInfoList - 입고 확정 상세 조회 */
SELECT *
  FROM TWORK_INFO_IBCF_DT
 WHERE CTKEY 	 	= #{ctkey}
   AND OWKEY 	 	= #{owkey}
   AND IBHDKEY 	 	= #{ibhdkey}
   AND IBDTKEY   	= #{ibdtkey}

/* wms-inbound-ibordermaganer-sql-oracle.xml - selectIbcfDtCntCheck - 입고 확정 상세 체크 */
