  FROM TWORK_INFO_IBCF_DT
 WHERE CTKEY 	 = #{ctkey}
   AND OWKEY 	 = #{owkey}
   AND IBHDKEY 	 = #{ibhdkey}
   AND IBDTKEY 	 = #{ibdtkey}
   AND IBCFSEQNO = #{ibcfseqno}

/* wms-inbound-ibordermaganer-sql-oracle.xml - selectIbcfDtMap - 입고 확정 상세 조회 */
SELECT *
  FROM TWORK_INFO_IBCF_DT
 WHERE CTKEY 	 = #{ctkey}
AND OWKEY 	 = #{owkey}
AND IBHDKEY 	 = #{ibhdkey}
AND IBDTKEY 	 = #{ibdtkey}
AND IBCFSEQNO = #{ibcfseqno}

/* wms-inbound-ibordermaganer-sql-oracle.xml - selectIbcfDtByPrdctdateAndExpdate - 입고 확정 조회 */
SELECT *
  FROM TWORK_INFO_IBCF_DT
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND ICKEY   = #{ickey}
   AND CNTRNO = #{cntrno}
   AND (EXPDATE = #{expdate} OR (EXPDATE IS NULL AND #{expdate} IS NULL))
   AND (PRDCTDATE = #{prdctdate} OR (PRDCTDATE IS NULL AND #{prdctdate} IS NULL))

/* wms-inbound-ibordermaganer-sql-oracle.xml - selectIbcfDtSeqno - 확정 상세 시퀀스 번호 조회 */
SELECT COALESCE(MAX(IBCFSEQNO) + 1, 1)
  FROM TWORK_INFO_IBCF_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = COALESCE(#{owkey}, #{sowkey})
   AND IBHDKEY = #{ibhdkey}

mapper.update:
/* wms-inbound-ibordermaganer-sql-oracle.xml - updateIbcfDtQty - 확정 상세 수량 무게 수정 */
UPDATE TWORK_INFO_IBCF_DT
   SET IBQTY        = IBQTY + #{ibqty}
     , CNFRMQTY     = CNFRMQTY + #{cnfrmqty}
     , WEIGHT       = WEIGHT + #{weight}
     , UPDATEDATE   = #{sysdate}
     , UPDATEURKEY  = #{surkey}
 WHERE CTKEY        = #{ctkey}
   AND OWKEY        = COALESCE(#{owkey}, #{sowkey})
   AND IBHDKEY      = #{ibhdkey}
   AND IBDTKEY      = #{ibdtkey}
   AND IBCFSEQNO    = #{ibcfseqno}

